import "@babel/polyfill";
import Vue from "vue";
import VueI18n from "vue-i18n";
import Vuetify from "vuetify";
import * as ms from "milsymbol";
import "vuetify/dist/vuetify.min.css";
import VueClipboard from "vue-clipboard2";
import vshortkey from "vue-shortkey";

import App from "./App.vue";
import router from "./router";
import store from "./store";
import { messages, readInitialLocale, applyDocumentLang } from "./i18n";

/* Roboto + Material Icons ship with the app (no Google Fonts CDN; works offline). */
import "typeface-roboto/index.css";
import "material-design-icons/iconfont/material-icons.css";

Vue.use(VueClipboard);
Vue.use(VueI18n);
Vue.use(Vuetify);
Vue.use(vshortkey);
Vue.config.productionTip = false;
ms.setStandard("APP6");

const locale = readInitialLocale();
applyDocumentLang(locale);

const i18n = new VueI18n({
  locale,
  fallbackLocale: "en",
  messages
});

window.addEventListener("message", event => {
  const d = event.data;
  if (!d || d.type !== "sidc-picker:setLocale") return;
  if (d.locale !== "ar" && d.locale !== "en") return;
  i18n.locale = d.locale;
  applyDocumentLang(d.locale);
});

new Vue({
  router,
  store,
  i18n,
  render: h => h(App)
}).$mount("#app");
