<template>
  <div>
    <v-list-tile :to="{ name: 'keyboardShortcuts' }">
      <v-list-tile-action>
        <v-icon>keyboard</v-icon>
      </v-list-tile-action>
      <v-list-tile-content>
        <v-list-tile-title>{{ $t("picker.drawer.shortcuts") }}</v-list-tile-title>
      </v-list-tile-content>
    </v-list-tile>
    <v-subheader>{{ $t("picker.drawer.actions") }}</v-subheader>
    <v-list-tile @click="doCopy">
      <v-list-tile-action>
        <v-icon>assignment</v-icon>
      </v-list-tile-action>
      <v-list-tile-content>
        <v-list-tile-title>{{ $t("picker.drawer.copySid") }}</v-list-tile-title>
      </v-list-tile-content>
    </v-list-tile>
    <v-list-tile
      :title="$t('picker.drawer.clearModsTitle')"
      @click="clear"
    >
      <v-list-tile-action>
        <v-icon>clear</v-icon>
      </v-list-tile-action>
      <v-list-tile-content>
        <v-list-tile-title>{{ $t("picker.drawer.clearMods") }}</v-list-tile-title>
      </v-list-tile-content>
    </v-list-tile>
    <v-list-tile @click="downloadPNG">
      <v-list-tile-action>
        <v-icon>save_alt</v-icon>
      </v-list-tile-action>
      <v-list-tile-content>
        <v-list-tile-title>{{ $t("picker.drawer.png") }}</v-list-tile-title>
      </v-list-tile-content>
    </v-list-tile>
    <v-list-tile @click="downloadSVG">
      <v-list-tile-action>
        <v-icon>save_alt</v-icon>
      </v-list-tile-action>
      <v-list-tile-content>
        <v-list-tile-title>{{ $t("picker.drawer.svg") }}</v-list-tile-title>
      </v-list-tile-content>
    </v-list-tile>
    <v-list-tile :to="permalink">
      <v-list-tile-action>
        <v-icon>link</v-icon>
      </v-list-tile-action>
      <v-list-tile-content>
        <v-list-tile-title>{{ $t("picker.drawer.permalink") }}</v-list-tile-title>
      </v-list-tile-content>
    </v-list-tile>
    <v-list-tile @click="saveSymbol">
      <v-list-tile-action>
        <v-icon>star</v-icon>
      </v-list-tile-action>
      <v-list-tile-content>
        <v-list-tile-title>{{ $t("picker.drawer.save") }}</v-list-tile-title>
      </v-list-tile-content>
    </v-list-tile>
    <v-subheader>{{ $t("picker.drawer.settings") }}</v-subheader>
    <v-list-tile>
      <v-list-tile-content>
        <v-radio-group
          v-model="standard"
          row
          class="pt-0 standard-group"
          :title="$t('picker.drawer.standardTitle')"
        >
          <v-radio label="APP6-D" value="APP6" />
          <v-radio label="2525-D" value="2525" />
        </v-radio-group>
      </v-list-tile-content>
    </v-list-tile>
    <v-list-tile @click="simpleStatusModifier = !simpleStatusModifier">
      <v-list-tile-action>
        <v-switch v-model="simpleStatusModifier" @click.stop />
      </v-list-tile-action>
      <v-list-tile-content>
        <v-list-tile-title>{{ $t("picker.drawer.simpleStatus") }}</v-list-tile-title>
      </v-list-tile-content>
    </v-list-tile>
    <v-list-tile
      :title="$t('picker.drawer.autocompleteTitle')"
      @click="autocomplete = !autocomplete"
    >
      <v-list-tile-action>
        <v-switch v-model="autocomplete" @click.stop />
      </v-list-tile-action>
      <v-list-tile-content>
        <v-list-tile-title>{{ $t("picker.drawer.autocomplete") }}</v-list-tile-title>
      </v-list-tile-content>
    </v-list-tile>
    <div style="display:none">
      <a v-shortkey="{ a: ['shift', '?'], b: ['?'] }" @shortkey="showHelp" />
    </div>
  </div>
</template>

<script>
import { ActionMixins, SettingsMixins } from "./mixins";

export default {
  mixins: [SettingsMixins, ActionMixins],
  methods: {
    showHelp() {
      this.$router.push({ name: "keyboardShortcuts" });
    }
  }
};
</script>

<style>
.list--dense .standard-group {
  margin-top: 6px !important;
}

.list--dense .standard-group label {
  font-size: 14px;
}
</style>
