import en from "./en";
import ar from "./ar";

export const messages = { en, ar };

/** Same key as rmooz client/i18n.js so ?lang= and postMessage stay aligned. */
const STORAGE_KEY = "rmooz-lang";

export function readInitialLocale() {
  try {
    const q = new URLSearchParams(window.location.search).get("lang");
    if (q === "ar" || q === "en") return q;
  } catch (e) {
    console.warn("sidc-picker: URLSearchParams failed", e);
  }
  try {
    const stored = window.localStorage.getItem(STORAGE_KEY);
    if (stored === "ar" || stored === "en") return stored;
  } catch (e) {
    console.warn("sidc-picker: localStorage read failed", e);
  }
  return "en";
}

export function applyDocumentLang(locale) {
  document.documentElement.setAttribute("lang", locale);
  document.documentElement.setAttribute("dir", locale === "ar" ? "rtl" : "ltr");
}
